// ============================================
// Filtra bancos activos y los divide en grupos de 1
// para esperar 30s entre cada banco (rate limit)
// ============================================

const items = $input.all();

const active = items.filter(item => {
  const v = item.json.activo;
  return v === true || v === 'TRUE' || v === 'true' || v === 'SI' || v === 'Sí';
});

if (active.length === 0) throw new Error('No hay bancos activos en el Sheets.');

const BATCH_SIZE = 1;
const batches = [];

for (let i = 0; i < active.length; i += BATCH_SIZE) {
  const chunk = active.slice(i, i + BATCH_SIZE).map(item => ({
    banco:         item.json.banco         || '',
    url:           item.json.url           || '',
    pdf_url:       item.json.pdf_url       || '',
    target_url:    item.json.target_url    || '',
    tipo_producto: item.json.tipo_producto || '',
    activo:        item.json.activo,
  }));

  batches.push({
    json: {
      batch_index:   i + 1,
      total_batches: active.length,
      banks:         chunk,
      banks_csv:     chunk.map(b =>
        `banco: ${b.banco} | url: ${b.url} | pdf_url: ${b.pdf_url}`
      ).join('\n'),
    }
  });
}

console.log(`${active.length} bancos activos → ${batches.length} lotes de 1`);
return batches;

// ============================================
// Construye el mensaje del agente con valores reales
// resolviendo todas las expresiones antes de Claude
// ============================================

const item = $input.first().json;

// Fecha en hora Bogotá
const now = new Date();
const bogota = new Date(now.toLocaleString('en-US', { timeZone: 'America/Bogota' }));

const pad = n => String(n).padStart(2, '0');
const meses = ['enero','febrero','marzo','abril','mayo','junio',
               'julio','agosto','septiembre','octubre','noviembre','diciembre'];

const year  = bogota.getFullYear();
const month = bogota.getMonth(); // 0-indexed

const prevMonth = month === 0 ? 11 : month - 1;
const prevYear  = month === 0 ? year - 1 : year;

const mesActualMin   = meses[month];
const mesActualTitle = mesActualMin.charAt(0).toUpperCase() + mesActualMin.slice(1);
const mesActualUp    = mesActualMin.toUpperCase();
const mesNumero      = pad(month + 1);
const mesAntMin      = meses[prevMonth];
const mesAntUp       = mesAntMin.toUpperCase();
const mesAntNumero   = pad(prevMonth + 1);
const fechaHoy       = `${pad(bogota.getDate())}/${mesNumero}/${year}`;

// banks_csv viene del nodo anterior (One Bank at a Time → Split Into Batches of 1)
const banksCSV   = item.banks_csv   || '';
const batchIndex = item.batch_index || 1;
const totalBatch = item.total_batches || 1;

const prompt = `Procesa el siguiente banco (${batchIndex} de ${totalBatch} en este lote):

=== DATOS DEL BANCO ===
${banksCSV}

=== FECHA ACTUAL (Bogotá) ===
- Fecha hoy: ${fechaHoy}
- Mes actual (minúsculas): ${mesActualMin}
- Mes actual (Title Case): ${mesActualTitle}
- Mes actual (MAYÚSCULAS): ${mesActualUp}
- Mes número (con cero): ${mesNumero}
- Año actual: ${year}
- Mes anterior (minúsculas): ${mesAntMin}
- Mes anterior (MAYÚSCULAS): ${mesAntUp}
- Mes anterior número: ${mesAntNumero}
- Año del mes anterior: ${prevYear}

=== TU TAREA ===
1. Analiza el campo pdf_url del banco mostrado arriba.
2. Si url contiene varias URLs separadas por comas, trátalas de forma INDEPENDIENTE y agregalas en la fila url separadas con comas como en el formato.
3. Para cada URL, infiere la versión actualizada al mes actual (${mesActualTitle} ${year}) 
   usando los parámetros de fecha provistos arriba.
4. Verifica cada URL candidata con Tool: Verify URL (HEAD request).
5. Si la verificación devuelve HTTP 200 o 206 → actualiza esa URL.
6. Si no responde → conserva la URL original en esa posición.
7. Al finalizar reporta el resultado con el formato definido en tus instrucciones.`;

return {
  json: {
    ...item,
    resolved_prompt: prompt,
  }
};
